<template>
	<view class="sheet-overlay" @tap.self="onClose">
		<view class="sheet-container" @tap.stop>
			<view class="drag-handle"></view>

			<!-- т»╝УѕфТаЈ -->
			<view class="sheet-nav">
				<view class="nav-btn" @click="onClose">
					<text class="nav-cancel">тЈќТХѕ</text>
				</view>
				<text class="sheet-title">{{ mode === 'login' ? 'уЎ╗тйЋ' : 'Т│етєї' }}</text>
				<view style="min-width: 44px;"></view>
			</view>

			<scroll-view class="sheet-scroll" scroll-y>
				<!-- ТеАт╝ЈтѕЄТЇб -->
				<view class="mode-switcher card">
					<view
						class="mode-tab"
						:class="{ 'mode-tab-active': mode === 'login' }"
						@click="mode = 'login'; clearError()"
					>
						<text class="mode-tab-text">уЎ╗тйЋ</text>
					</view>
					<view
						class="mode-tab"
						:class="{ 'mode-tab-active': mode === 'register' }"
						@click="mode = 'register'; clearError()"
					>
						<text class="mode-tab-text">Т│етєї</text>
					</view>
				</view>

				<!-- жћЎУ»»ТЈљуц║ -->
				<view v-if="errorMsg" class="error-banner">
					<text class="error-text">{{ errorMsg }}</text>
				</view>

				<!-- УАетЇЋ -->
				<view class="form-card card">
					<view class="form-row">
						<text class="form-label">жѓ«у«▒</text>
						<input
							class="form-input"
							v-model="email"
							type="email"
							placeholder="УЙЊтЁЦжѓ«у«▒..."
							placeholder-class="form-placeholder"
						/>
					</view>
					<view class="form-divider"></view>
					<view class="form-row">
						<text class="form-label">т»єуаЂ</text>
						<input
							class="form-input"
							v-model="password"
							type="password"
							placeholder="УЙЊтЁЦт»єуаЂ..."
							placeholder-class="form-placeholder"
						/>
					</view>

					<template v-if="mode === 'register'">
						<view class="form-divider"></view>
						<view class="form-row">
							<text class="form-label">уА«У«цт»єуаЂ</text>
							<input
								class="form-input"
								v-model="confirmPassword"
								type="password"
								placeholder="тєЇТгАУЙЊтЁЦ..."
								placeholder-class="form-placeholder"
							/>
						</view>
						<view v-if="confirmPasswordMismatch" class="field-error-row">
							<text class="field-error-text">т»єуаЂСИјуА«У«цт»єуаЂСИЇСИђУЄ┤</text>
						</view>
						<view class="form-divider"></view>
						<view class="form-row">
							<text class="form-label">ТўхуД░</text>
							<input
								class="form-input"
								v-model="nickname"
								placeholder="жђЅтАФ..."
								placeholder-class="form-placeholder"
							/>
						</view>
					</template>
				</view>

				<!-- ТЈљС║цТїЅжњ« -->
				<view class="submit-btn-wrap">
					<view
						class="submit-btn"
						:class="{ 'submit-btn-disabled': !canSubmit }"
						@click="onSubmit"
					>
						<text class="submit-btn-text">{{ mode === 'login' ? 'уЎ╗тйЋ' : 'Т│етєї' }}</text>
					</view>
				</view>

				<!-- т║ЋжЃеУ»┤Тўј -->
				<text class="bottom-note">Т│етєї/уЎ╗тйЋтљјУ┤дТѕиСИјтЈЉжђЂУ«Йуй«т░єтљїТГЦУЄ│С║ЉуФ»сђѓ</text>

				<view style="height: 40px;"></view>
			</scroll-view>
		</view>
	</view>
</template>

<script>
	import { store, mutations } from '../../store/index.js'

	export default {
		name: 'LoginRegisterSheet',
		emits: ['close'],
		data() {
			return {
				mode: 'login',
				email: '',
				password: '',
				confirmPassword: '',
				nickname: '',
				errorMsg: ''
			}
		},
		computed: {
			canSubmit() {
				if (!this.email.trim() || !this.password.trim()) return false
				if (this.mode === 'register') {
					return this.password.length >= 6 && this.password === this.confirmPassword
				}
				return true
			},
			confirmPasswordMismatch() {
				if (this.mode !== 'register') return false
				return this.confirmPassword.length > 0 && this.password !== this.confirmPassword
			}
		},
		methods: {
			onClose() {
				this.$emit('close')
			},
			clearError() {
				this.errorMsg = ''
				if (this.mode === 'login') {
					this.confirmPassword = ''
				}
			},
			isValidEmail(email) {
				return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)
			},
			async onSubmit() {
				if (!this.canSubmit) return
				this.errorMsg = ''

				if (!this.isValidEmail(this.email)) {
					this.errorMsg = 'жѓ«у«▒Та╝т╝ЈТЌаТЋѕ'
					return
				}

				if (this.mode === 'login') {
					await this.doLogin()
				} else {
					if (this.password.length < 6) {
						this.errorMsg = 'т»єуаЂУЄ│т░ЉжюђУдЂ6СйЇ'
						return
					}
					if (this.password !== this.confirmPassword) {
						this.errorMsg = 'т»єуаЂСИјуА«У«цт»єуаЂСИЇСИђУЄ┤'
						return
					}
					await this.doRegister()
				}
			},
			async doLogin() {
				uni.showLoading({ title: 'уЎ╗тйЋСИГ№╝їУ»иуеЇтљј...', mask: true })
				try {
					const obj = uniCloud.importObject('register', { customUI: true })
					const res = await obj.login(this.email.trim(), this.password)
					if (res.errCode === 0) {
						this.saveTokenAndUser(res.newToken, res.userInfo)
						this.$emit('close')
						// уЎ╗тйЋТѕљтіЪтљјт╝ѓТГЦУ«░тйЋуЎ╗тйЋТЌХжЌ┤№╝їСИЇУДдтЈЉж╗ўУ«цсђїтіаУййСИГ...сђЇ
						const uid = res.userInfo && res.userInfo._id
						if (uid) {
							uniCloud.importObject('login', { customUI: true }).recordLoginTime(uid).catch(() => {})
						}
					} else {
						this.errorMsg = res.errMsg || (res.errCode === 'USER_NOT_FOUND' ? 'У»Цжѓ«у«▒т░џТюфТ│етєї' : 'уЎ╗тйЋтц▒У┤Ц')
					}
				} catch (e) {
					this.errorMsg = e.message || 'уйЉу╗ют╝ѓтИИ№╝їУ»ижЄЇУ»Ћ'
				} finally {
					uni.hideLoading()
				}
			},
			async doRegister() {
				try {
					const obj = uniCloud.importObject('register')
					const res = await obj.registerUser(this.email.trim(), this.password, this.nickname)
					if (res.errCode === 0) {
						this.saveTokenAndUser(res.newToken, res.userInfo)
						this.$emit('close')
					} else {
						this.errorMsg = res.errMsg || (res.errCode === 'EMAIL_EXISTS' ? 'У»Цжѓ«у«▒ти▓Т│етєї' : 'Т│етєїтц▒У┤Ц')
					}
				} catch (e) {
					this.errorMsg = e.message || 'уйЉу╗ют╝ѓтИИ№╝їУ»ижЄЇУ»Ћ'
				}
			},
			saveTokenAndUser(newToken, userInfo) {
				if (newToken && newToken.token) {
					uni.setStorageSync('uni_id_token', newToken.token)
					if (newToken.tokenExpired != null) {
						uni.setStorageSync('uni_id_token_expired', newToken.tokenExpired)
					}
				}
				const u = userInfo || {}
				mutations.setUser({ _id: u._id, email: u.email || this.email, nickname: u.nickname || this.nickname })
			},
			getStoredUsers() {
				try {
					const v = uni.getStorageSync('users')
					return v ? JSON.parse(v) : []
				} catch (e) {
					return []
				}
			}
		}
	}
</script>

<style scoped>
	.sheet-overlay {
		position: fixed;
		top: 0; left: 0; right: 0; bottom: 0;
		background-color: rgba(0, 0, 0, 0.4);
		z-index: 1000;
		display: flex;
		flex-direction: column;
		justify-content: flex-end;
	}

	.sheet-container {
		background-color: #F2F2F7;
		border-radius: 16px 16px 0 0;
		max-height: 85vh;
		display: flex;
		flex-direction: column;
		padding-bottom: env(safe-area-inset-bottom, 0px);
	}

	.drag-handle {
		width: 36px; height: 5px;
		background-color: #C7C7CC;
		border-radius: 3px;
		margin: 10px auto 4px;
	}

	.sheet-nav {
		display: flex;
		flex-direction: row;
		align-items: center;
		justify-content: space-between;
		padding: 8px 16px 12px;
	}

	.sheet-title {
		font-size: 17px;
		font-weight: 600;
		color: #1C1C1E;
	}

	.nav-btn { min-width: 44px; }

	.nav-cancel {
		font-size: 17px;
		color: #8E8E93;
		background-color: #E5E5EA;
		padding: 6px 14px;
		border-radius: 20px;
	}

	.sheet-scroll { flex: 1; }

	.mode-switcher {
		margin: 0 16px 16px;
		background: #FFFFFF;
		border-radius: 12px;
		display: flex;
		flex-direction: row;
		overflow: hidden;
	}

	.mode-tab {
		flex: 1;
		height: 42px;
		display: flex;
		align-items: center;
		justify-content: center;
		background-color: #F2F2F7;
	}

	.mode-tab-active {
		background-color: #FFFFFF;
		border-bottom: 2px solid #007AFF;
	}

	.mode-tab-text {
		font-size: 16px;
		font-weight: 500;
		color: #8E8E93;
	}

	.mode-tab-active .mode-tab-text {
		color: #1C1C1E;
	}

	.error-banner {
		margin: 0 16px 12px;
		background-color: #FFE5E5;
		border-radius: 10px;
		padding: 10px 14px;
	}

	.error-text {
		font-size: 14px;
		color: #C0392B;
	}

	.form-card {
		margin: 0 16px 16px;
		background: #FFFFFF;
		border-radius: 12px;
		overflow: hidden;
	}

	.form-row {
		display: flex;
		flex-direction: row;
		align-items: center;
		padding: 14px 16px;
		gap: 12px;
	}

	.form-label {
		font-size: 16px;
		color: #1C1C1E;
		min-width: 70px;
	}

	.form-input {
		flex: 1;
		font-size: 15px;
		color: #1C1C1E;
		background: transparent;
		border: none;
		outline: none;
	}

	.form-placeholder { color: #C7C7CC; }

	.form-divider {
		height: 0.5px;
		background-color: #E5E5EA;
		margin: 0 16px;
	}

	.field-error-row {
		padding: 4px 16px 8px;
		padding-left: calc(70px + 16px + 12px);
	}

	.field-error-text {
		font-size: 13px;
		color: #C0392B;
	}

	.submit-btn-wrap {
		padding: 0 16px 12px;
	}

	.submit-btn {
		width: 100%;
		height: 52px;
		background-color: #007AFF;
		border-radius: 14px;
		display: flex;
		align-items: center;
		justify-content: center;
	}

	.submit-btn-disabled {
		opacity: 0.5;
	}

	.submit-btn-text {
		font-size: 17px;
		font-weight: 600;
		color: #FFFFFF;
	}

	.bottom-note {
		font-size: 13px;
		color: #8E8E93;
		text-align: center;
		padding: 4px 20px;
	}
</style>
